import Link from 'next/link';
import { Leaf } from 'lucide-react';

export default function NotFound() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-cream">
      <div className="text-center px-6">
        <div className="size-20 rounded-full bg-primary/10 flex items-center justify-center mx-auto mb-6">
          <Leaf className="text-primary" size={36} />
        </div>
        <h1 className="gc-display text-6xl font-bold text-primary mb-2">404</h1>
        <h2 className="gc-display text-2xl text-text mb-3">Page Not Found</h2>
        <p className="text-sm text-muted font-medium mb-8 max-w-md mx-auto">
          Oops! The page you&apos;re looking for seems to have wandered off into the organic fields.
        </p>
        <div className="flex gap-3 justify-center">
          <Link
            href="/"
            className="gc-display inline-flex items-center gap-2 px-6 py-3 rounded-2xl bg-primary text-white font-semibold text-sm hover:bg-primary-light transition-colors"
          >
            Go Home
          </Link>
          <Link
            href="/shop"
            className="gc-display inline-flex items-center gap-2 px-6 py-3 rounded-2xl border border-primary text-primary font-semibold text-sm hover:bg-primary hover:text-white transition-colors"
          >
            Shop Products
          </Link>
        </div>
      </div>
    </div>
  );
}
